    function createParameterRow(param, index) {
        const row = document.createElement('tr');
        row.dataset.parameterId = param.id;
        row.draggable = true;

        // Get German description
        const deTranslation = param.translations.find(t => t.language_code === 'de');
        const descriptionDe = deTranslation ? deTranslation.description : '';

        // Handle default_value display
        let defaultValueDisplay = '';
        if (param.default_value_json) {
            try {
                const parsedValue = JSON.parse(param.default_value_json);
                if (typeof parsedValue === 'object' && parsedValue !== null) {
                    defaultValueDisplay = Array.isArray(parsedValue) ? `[Array ${parsedValue.length}]` : `{Dict}`;
                } else {
                    defaultValueDisplay = parsedValue;
                }
            } catch (e) {
                defaultValueDisplay = param.default_value_json;
            }
        }

        row.innerHTML = `
            <td><input type="checkbox" class="param-checkbox" data-param-id="${param.id}"></td>
            <td class="drag-handle"><i class="fas fa-grip-vertical"></i></td>
            <td><span class="param-type">${param.gdl_type}</span></td>
            <td class="editable" data-field="gdl_name">${param.gdl_name}</td>
            <td class="editable" data-field="description_de">${descriptionDe}</td>
            <td class="editable" data-field="default_value">${defaultValueDisplay}</td>
