            <td><input type="checkbox" class="flag-checkbox" data-field="is_ui_element" ${param.is_ui_element ? 'checked' : ''}></td>
            <td>${param.array_type !== 'None' ? param.array_type : ''}</td>
        `;

        // Event listeners
        row.querySelector('.param-checkbox').addEventListener('change', handleCheckboxChange);
        row.querySelectorAll('.flag-checkbox').forEach(cb => cb.addEventListener('change', (e) => handleFlagChange(param.id, e)));
        row.querySelectorAll('.editable').forEach(cell => {
            cell.addEventListener('click', () => makeEditable(cell, param.id));
        });
        row.addEventListener('click', (e) => {
            if (!e.target.closest('input') && !e.target.closest('.editable')) {
                selectParameter(param);
            }
        });

        // Drag & Drop
        row.addEventListener('dragstart', handleDragStart);
        row.addEventListener('dragover', handleDragOver);
        row.addEventListener('drop', handleDrop);
        row.addEventListener('dragend', handleDragEnd);

        return row;
    }

    // ===== INLINE EDITING =====
    function makeEditable(cell, parameterId) {
        if (cell.querySelector('input')) return; // Already editing

        const originalValue = cell.textContent.trim();
        const field = cell.dataset.field;

        const input = document.createElement('input');
        input.type = 'text';
        input.value = originalValue;
        input.style.width = '100%';
        input.style.padding = '4px';
        input.style.border = '1px solid var(--accent-color)';
        input.style.backgroundColor = '#4c566a';
        input.style.color = 'var(--text-color)';

        cell.innerHTML = '';
        cell.appendChild(input);
        input.focus();
        input.select();

        const saveEdit = async () => {
            const newValue = input.value.trim();
            if (newValue !== originalValue) {
                await updateParameterField(parameterId, field, newValue);
            }
            cell.textContent = newValue || originalValue;
        };

        input.addEventListener('blur', saveEdit);
        input.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                input.blur();
            }
        });
    }

    async function updateParameterField(parameterId, field, value) {
        const updateData = {};

        if (field === 'description_de') {
            // Update translation
            const param = allParameters.find(p => p.id === parameterId);
            const translations = param.translations.map(t => ({
                ...t,
                description: t.language_code === 'de' ? value : t.description
            }));
            updateData.translations = translations;
        } else {
            updateData[field] = value;
        }

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${parameterId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updateData)
            });

            if (response.ok) {
                // Update local data
                const param = allParameters.find(p => p.id === parameterId);
                if (field === 'description_de') {
                    const deTranslation = param.translations.find(t => t.language_code === 'de');
                    if (deTranslation) deTranslation.description = value;
                } else {
                    param[field] = value;
                }
                statusMessage.textContent = 'Status: Änderung gespeichert.';
            } else {
                const result = await response.json();
                statusMessage.textContent = `Fehler beim Speichern: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    async function handleFlagChange(parameterId, event) {
        const field = event.target.dataset.field;
        const value = event.target.checked;

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${parameterId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ [field]: value })
            });

            if (response.ok) {
                const param = allParameters.find(p => p.id === parameterId);
                param[field] = value;
                statusMessage.textContent = 'Status: Flag gespeichert.';
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== SELECTION & RIGHT PANEL =====
    function selectParameter(param) {
        // Highlight row
        document.querySelectorAll('#parameterTableBody tr').forEach(r => r.classList.remove('selected'));
        const row = document.querySelector(`tr[data-parameter-id="${param.id}"]`);
        if (row) row.classList.add('selected');

        currentEditingParam = param;
        updateRightPanel(param);
    }

    function updateRightPanel(param) {
        const rightPanel = document.querySelector('.right-panel');
        if (!rightPanel || !param) return;

        rightPanel.querySelector('input[name="param_name"]').value = param.gdl_name || '';
        rightPanel.querySelector('select[name="param_type"]').value = param.gdl_type || 'Length';
        rightPanel.querySelector('select[name="param_function"]').value = param.function_group || 'Geometrie';
        rightPanel.querySelector('select[name="param_array_type"]').value = param.array_type || 'None';
        rightPanel.querySelector('input[name="flag_fix_name"]').checked = param.is_fix_name;
        rightPanel.querySelector('input[name="flag_unique"]').checked = param.flag_unique;
        rightPanel.querySelector('input[name="flag_bold"]').checked = param.flag_bold;
        rightPanel.querySelector('input[name="flag_child"]').checked = param.flag_child;
        rightPanel.querySelector('input[name="flag_hidden"]').checked = param.flag_hidden;
        rightPanel.querySelector('input[name="param_ui_page"]').value = param.ui_page || 0;
        rightPanel.querySelector('textarea[name="param_ui_code"]').value = param.ui_code || '';

        // Update translations
        param.translations.forEach(t => {
            const langContent = rightPanel.querySelector(`.lang-content[data-lang="${t.language_code}"]`);
            if (langContent) {
                langContent.querySelector('input[name="desc_lang"]').value = t.description || '';
                langContent.querySelector('input[name="default_val_lang"]').value = param.default_value_json || '';
                langContent.querySelector('textarea[name="values_list_lang"]').value = t.values_list || '';
                langContent.querySelector('textarea[name="ui_tooltip_lang"]').value = t.ui_tooltip || '';
            }
        });
    }

    async function updateParameterFromRightPanel() {
        if (!currentEditingParam) return;

        const rightPanel = document.querySelector('.right-panel');
        const activeLang = rightPanel.querySelector('.lang-tab.active').dataset.lang;
        const activeLangContent = rightPanel.querySelector(`.lang-content[data-lang="${activeLang}"]`);

        const updateData = {
            gdl_name: rightPanel.querySelector('input[name="param_name"]').value,
            gdl_type: rightPanel.querySelector('select[name="param_type"]').value,
            function_group: rightPanel.querySelector('select[name="param_function"]').value,
            array_type: rightPanel.querySelector('select[name="param_array_type"]').value,
            is_fix_name: rightPanel.querySelector('input[name="flag_fix_name"]').checked,
            flag_unique: rightPanel.querySelector('input[name="flag_unique"]').checked,
            flag_bold: rightPanel.querySelector('input[name="flag_bold"]').checked,
            flag_child: rightPanel.querySelector('input[name="flag_child"]').checked,
            flag_hidden: rightPanel.querySelector('input[name="flag_hidden"]').checked,
            ui_page: parseInt(rightPanel.querySelector('input[name="param_ui_page"]').value),
            ui_code: rightPanel.querySelector('textarea[name="param_ui_code"]').value,
            translations: [{
                language_code: activeLang,
                description: activeLangContent.querySelector('input[name="desc_lang"]').value,
                values_list: activeLangContent.querySelector('textarea[name="values_list_lang"]').value,
                ui_tooltip: activeLangContent.querySelector('textarea[name="ui_tooltip_lang"]').value
            }]
        };

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${currentEditingParam.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updateData)
            });

            if (response.ok) {
                Object.assign(currentEditingParam, updateData);
                await loadParameters(currentProjectId); // Reload to refresh display
                statusMessage.textContent = 'Status: Parameter aktualisiert.';
            }
        } catch (error) {
            statusMessage.textContent = `Fehler beim Speichern: ${error.message}`;
        }
    }

    // ===== ADD PARAMETER =====
    function showAddParameterDialog() {
        if (!currentProjectId) {
            alert('Bitte erstellen oder laden Sie zuerst ein Projekt.');
            return;
        }

        const paramName = prompt('Neuen Parameter erstellen\n\nBitte geben Sie den Parameternamen ein:');

        if (paramName && paramName.trim()) {
            addParameter(paramName.trim());
        }
    }

    async function addParameter(gdlName) {
        try {
            const response = await fetch(`${API_BASE_URL}/parameters/create`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    project_id: currentProjectId,
                    gdl_name: gdlName,
                    gdl_type: 'String',
                    translations: [
                        { language_code: 'de', description: gdlName },
                        { language_code: 'en', description: gdlName }
                    ]
                })
            });

            const result = await response.json();

            if (response.ok) {
                statusMessage.textContent = `Status: Parameter "${gdlName}" erstellt.`;
                await loadParameters(currentProjectId);
            } else {
                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== DELETE PARAMETERS =====
    function handleCheckboxChange(event) {
        const parameterId = parseInt(event.target.dataset.paramId);

        if (event.target.checked) {
            selectedParameterIds.add(parameterId);
        } else {
            selectedParameterIds.delete(parameterId);
        }

        updateDeleteButtonState();
    }

    function updateDeleteButtonState() {
        const deleteBtn = document.querySelector('.action-btn.delete-param');

        if (selectedParameterIds.size > 0) {
            deleteBtn.classList.remove('disabled');
        } else {
            deleteBtn.classList.add('disabled');
        }
    }

    async function deleteSelectedParameters() {
        if (selectedParameterIds.size === 0) return;

        const confirmed = confirm(`Möchten Sie wirklich ${selectedParameterIds.size} Parameter löschen?`);
        if (!confirmed) return;

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/bulk-delete`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ parameter_ids: Array.from(selectedParameterIds) })
            });

            const result = await response.json();

            if (response.ok) {
                statusMessage.textContent = `Status: ${result.deleted_count} Parameter gelöscht.`;
                selectedParameterIds.clear();
                await loadParameters(currentProjectId);
            } else {
                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== DRAG & DROP REORDERING =====
    let draggedRow = null;

    function handleDragStart(e) {
        draggedRow = this;
        this.style.opacity = '0.4';
        e.dataTransfer.effectAllowed = 'move';
    }

    function handleDragOver(e) {
        if (e.preventDefault) {
            e.preventDefault();
        }
        e.dataTransfer.dropEffect = 'move';

        const targetRow = e.target.closest('tr');
        if (targetRow && targetRow !== draggedRow) {
            const rect = targetRow.getBoundingClientRect();
            const midpoint = rect.top + rect.height / 2;

            if (e.clientY < midpoint) {
                targetRow.parentNode.insertBefore(draggedRow, targetRow);
            } else {
                targetRow.parentNode.insertBefore(draggedRow, targetRow.nextSibling);
            }
        }

        return false;
    }

    function handleDrop(e) {
        if (e.stopPropagation) {
            e.stopPropagation();
        }
        return false;
    }

    async function handleDragEnd(e) {
        this.style.opacity = '1';

        // Get new order
        const rows = Array.from(parameterTableBody.querySelectorAll('tr'));
        const orderedIds = rows.map(row => parseInt(row.dataset.parameterId)).filter(id => !isNaN(id));

        if (orderedIds.length > 0) {
            await saveParameterOrder(orderedIds);
        }
    }

    async function saveParameterOrder(orderedIds) {
        try {
            const response = await fetch(`${API_BASE_URL}/parameters/reorder`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ ordered_ids: orderedIds })
            });

            if (response.ok) {
                statusMessage.textContent = 'Status: Reihenfolge gespeichert.';
                // Update local order
                const newOrder = [];
                orderedIds.forEach(id => {
                    const param = allParameters.find(p => p.id === id);
                    if (param) newOrder.push(param);
                });
                allParameters = newOrder;
            }
        } catch (error) {
            statusMessage.textContent = `Fehler beim Speichern der Reihenfolge: ${error.message}`;
        }
    }

    // ===== FILTER =====
    function filterParameters() {
        const filterText = filterInput.value.toLowerCase();
        const rows = parameterTableBody.querySelectorAll('tr');

        rows.forEach(row => {
            const text = row.textContent.toLowerCase();
            row.style.display = text.includes(filterText) ? '' : 'none';
        });
    }

    // ===== EXPORT XML =====
    async function exportXml(projectId) {
        if (!projectId) {
            alert('Kein Projekt geladen.');
            return;
        }

        try {
            statusMessage.textContent = 'Status: XML wird generiert...';

            const response = await fetch(`${API_BASE_URL}/parameters/${projectId}/export`);

            if (response.ok) {
                const blob = await response.blob();
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `${currentProjectName.replace('.gsm', '')}_parameters.xml`;
                document.body.appendChild(a);
                a.click();
                window.URL.revokeObjectURL(url);
                document.body.removeChild(a);

                statusMessage.textContent = 'Status: XML erfolgreich exportiert.';
            } else {
                statusMessage.textContent = 'Fehler beim XML-Export.';
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }
});
</script>
