                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    async function selectProject(projectId, projectName) {
        currentProjectId = projectId;
        currentProjectName = projectName;
        localStorage.setItem('gdl_current_project_id', projectId);
        localStorage.setItem('gdl_current_project_name', projectName);

        // Clear object selection
        currentGdlObjectId = null;
        currentGdlObjectName = null;
        localStorage.removeItem('gdl_current_object_id');
        localStorage.removeItem('gdl_current_object_name');

        updateHeaderDisplay();
        await showGdlObjectDialog();
    }

    async function showLoadProjectDialog() {
        await showProjectDialog();
    }

    // ===== GDL OBJECT MANAGEMENT =====
    async function showGdlObjectDialog() {
        if (!currentProjectId) {
            alert('Bitte erstellen oder laden Sie zuerst ein Projekt.');
            await showProjectDialog();
            return;
        }

        try {
            const response = await fetch(`${API_BASE_URL}/projects/${currentProjectId}/objects`);
            const result = await response.json();

            let message = '=== GDL-OBJEKT AUSWÄHLEN ===\n\n';

            if (response.ok && result.gdl_objects.length > 0) {
                message += `Projekt: ${currentProjectName}\n\n`;
                message += 'Verfügbare GDL-Objekte:\n';
                result.gdl_objects.forEach((obj, index) => {
                    message += `${index + 1}. ${obj.name} (${obj.parameter_count} Parameter)\n`;
                });
                message += '\n0. Neues GDL-Objekt erstellen\n';
                message += '\nGeben Sie die Nummer ein:';

                const choice = prompt(message);

                if (choice === '0') {
                    await createNewGdlObject();
                } else {
                    const index = parseInt(choice) - 1;
                    if (index >= 0 && index < result.gdl_objects.length) {
                        const obj = result.gdl_objects[index];
                        await selectGdlObject(obj.id, obj.name);
                    }
                }
            } else {
                await createNewGdlObject();
            }
        } catch (error) {
            statusMessage.textContent = `Fehler: ${error.message}`;
        }
    }

    async function createNewGdlObject() {
        const objectName = prompt('Neues GDL-Objekt erstellen\n\nObjektname eingeben (z.B. "Fenster_01.gsm"):');

        if (objectName && objectName.trim()) {
            await createGdlObject(objectName.trim());
        }
    }

    async function createGdlObject(objectName) {
        try {
            statusMessage.textContent = 'Status: GDL-Objekt wird erstellt...';

            const response = await fetch(`${API_BASE_URL}/objects`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ 
                    project_id: currentProjectId,
                    name: objectName 
                })
            });

            const result = await response.json();

            if (response.ok) {
                await selectGdlObject(result.objectId, objectName);
                statusMessage.textContent = `Status: GDL-Objekt "${objectName}" erstellt.`;
            } else if (response.status === 409) {
                const useExisting = confirm(`GDL-Objekt "${objectName}" existiert bereits.\n\nMöchten Sie dieses Objekt laden?`);
                if (useExisting && result.existingObjectId) {
                    await selectGdlObject(result.existingObjectId, objectName);
                }
            } else {
                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    async function selectGdlObject(objectId, objectName) {
        currentGdlObjectId = objectId;
        currentGdlObjectName = objectName;
        localStorage.setItem('gdl_current_object_id', objectId);
        localStorage.setItem('gdl_current_object_name', objectName);

        updateHeaderDisplay();
        await loadParameters(objectId);
    }

    // ===== XML IMPORT =====
    async function handleXmlImport(event) {
        const file = event.target.files[0];
        if (!file) return;

        const objectName = prompt(
            `XML-Import\n\nDatei: ${file.name}\n\n` +
            'Name des GDL-Objekts eingeben\n' +
            '(oder leer lassen für automatische Erkennung):',
            file.name.replace('.xml', '').replace('_Param', '') + '.gsm'
        );

        if (!objectName) {
            statusMessage.textContent = 'Status: Import abgebrochen.';
            xmlFileInput.value = ''; // Reset file input
            return;
        }

        statusMessage.textContent = 'Status: XML-Datei wird gelesen...';

        const reader = new FileReader();
        reader.onload = async (e) => {
            const xmlContent = e.target.result;

            statusMessage.textContent = 'Status: Parameter werden importiert...';

            try {
                const response = await fetch(`${API_BASE_URL}/parameters/import`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        xml_content: xmlContent,
                        project_id: currentProjectId,
                        object_name: objectName,
                    }),
                });

                const result = await response.json();

                if (response.ok) {
                    statusMessage.textContent = `Status: ${result.message}`;
                    await selectGdlObject(result.gdlObjectId, result.objectName);
                } else {
                    statusMessage.textContent = `Fehler: ${result.error || 'Unbekannter Fehler'}`;
                    console.error('Import failed:', result);
                }
            } catch (error) {
                statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
                console.error('Network error:', error);
            }

            xmlFileInput.value = ''; // Reset file input
        };
        reader.readAsText(file);
    }

    // ===== LOAD PARAMETERS =====
    async function loadParameters(objectId) {
        if (!objectId) {
            statusMessage.textContent = 'Status: Kein GDL-Objekt ausgewählt.';
            parameterTableBody.innerHTML = '<tr><td colspan="13" style="text-align: center; color: #8899a6; padding: 15px;">Bitte wählen Sie ein GDL-Objekt aus.</td></tr>';
            rowCountSpan.textContent = 'Zeilen: 0';
            return;
        }

        statusMessage.textContent = 'Status: Parameter werden geladen...';

        try {
            const response = await fetch(`${API_BASE_URL}/objects/${objectId}/parameters`);
            const data = await response.json();

            if (response.ok) {
                allParameters = data.parameters || [];
                renderParameters();
                statusMessage.textContent = 'Status: Parameter erfolgreich geladen.';
            } else {
                statusMessage.textContent = `Fehler beim Laden: ${data.error || 'Unbekannter Fehler'}`;
                console.error('Failed to load parameters:', data);
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler beim Laden: ${error.message}`;
            console.error('Network error:', error);
        }
    }

    // ===== RENDER PARAMETERS =====
    function renderParameters() {
        parameterTableBody.innerHTML = '';

        if (allParameters.length === 0) {
            parameterTableBody.innerHTML = '<tr><td colspan="13" style="text-align: center; color: #8899a6; padding: 15px;">Keine Parameter vorhanden. Importieren Sie eine XML-Datei oder erstellen Sie einen neuen Parameter.</td></tr>';
            rowCountSpan.textContent = 'Zeilen: 0';
            return;
        }

        allParameters.forEach((param, index) => {
            const row = createParameterRow(param, index);
            parameterTableBody.appendChild(row);
        });

        rowCountSpan.textContent = `Zeilen: ${allParameters.length}`;
        updateDeleteButtonState();
    }

    function createParameterRow(param, index) {
        const row = document.createElement('tr');
        row.dataset.parameterId = param.id;
        row.draggable = true;

        // Get German description
        const deTranslation = param.translations.find(t => t.language_code === 'de');
        const descriptionDe = deTranslation ? deTranslation.description : '';

        // Handle default_value display
        let defaultValueDisplay = '';
        if (param.default_value_json) {
            try {
                const parsedValue = JSON.parse(param.default_value_json);
                if (typeof parsedValue === 'object' && parsedValue !== null) {
                    defaultValueDisplay = Array.isArray(parsedValue) ? `[Array ${parsedValue.length}]` : `{Dict}`;
                } else {
                    defaultValueDisplay = parsedValue;
                }
            } catch (e) {
                defaultValueDisplay = param.default_value_json;
            }
        }

        // Create type dropdown
        const typeSelectHtml = `
            <select class="param-type-select param-table-select" data-param-id="${param.id}">
                ${GDL_TYPES.map(type => 
                    `<option value="${type}" ${param.gdl_type === type ? 'selected' : ''}>${type}</option>`
                ).join('')}
            </select>
        `;

        row.innerHTML = `
            <td><input type="checkbox" class="param-checkbox" data-param-id="${param.id}"></td>
            <td class="drag-handle"><i class="fas fa-grip-vertical"></i></td>
            <td>${typeSelectHtml}</td>
            <td class="editable" data-field="gdl_name">${param.gdl_name}</td>
            <td class="editable" data-field="description_de">${descriptionDe}</td>
            <td class="editable" data-field="default_value">${defaultValueDisplay}</td>
            <td><input type="checkbox" class="flag-checkbox" data-field="flag_bold" ${param.flag_bold ? 'checked' : ''}></td>
            <td><input type="checkbox" class="flag-checkbox" data-field="flag_child" ${param.flag_child ? 'checked' : ''}></td>
            <td><input type="checkbox" class="flag-checkbox" data-field="flag_hidden" ${param.flag_hidden ? 'checked' : ''}></td>
            <td><input type="checkbox" class="flag-checkbox" data-field="flag_unique" ${param.flag_unique ? 'checked' : ''}></td>
            <td class="editable" data-field="ui_page">${param.ui_page || 0}</td>
            <td><input type="checkbox" class="flag-checkbox" data-field="is_ui_element" ${param.is_ui_element ? 'checked' : ''}></td>
            <td>${param.array_type !== 'None' ? param.array_type : ''}</td>
        `;

        // Event listeners
        row.querySelector('.param-checkbox').addEventListener('change', handleCheckboxChange);
        row.querySelector('.param-type-select').addEventListener('change', (e) => handleTypeChange(param.id, e));
        row.querySelectorAll('.flag-checkbox').forEach(cb => cb.addEventListener('change', (e) => handleFlagChange(param.id, e)));
        row.querySelectorAll('.editable').forEach(cell => {
            cell.addEventListener('click', () => makeEditable(cell, param.id));
        });
        row.addEventListener('click', (e) => {
            if (!e.target.closest('input') && !e.target.closest('select') && !e.target.closest('.editable')) {
                selectParameter(param);
            }
        });

        // Drag & Drop
        row.addEventListener('dragstart', handleDragStart);
        row.addEventListener('dragover', handleDragOver);
        row.addEventListener('drop', handleDrop);
        row.addEventListener('dragend', handleDragEnd);

        return row;
    }

    // ===== TYPE CHANGE IN TABLE =====
    async function handleTypeChange(parameterId, event) {
        const newType = event.target.value;

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${parameterId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ gdl_type: newType })
            });

            if (response.ok) {
                const param = allParameters.find(p => p.id === parameterId);
                param.gdl_type = newType;
                statusMessage.textContent = 'Status: Typ geändert.';

                // Update right panel if this param is selected
                if (currentEditingParam && currentEditingParam.id === parameterId) {
                    document.querySelector('select[name="param_type"]').value = newType;
                }
            } else {
                const result = await response.json();
                statusMessage.textContent = `Fehler: ${result.error}`;
                event.target.value = allParameters.find(p => p.id === parameterId).gdl_type; // Revert
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
            event.target.value = allParameters.find(p => p.id === parameterId).gdl_type; // Revert
        }
    }

    // ===== INLINE EDITING =====
    function makeEditable(cell, parameterId) {
        if (cell.querySelector('input')) return;

        const originalValue = cell.textContent.trim();
        const field = cell.dataset.field;

        const input = document.createElement('input');
        input.type = 'text';
        input.value = originalValue;
        input.style.width = '100%';
        input.style.padding = '4px';
        input.style.border = '1px solid var(--accent-color)';
        input.style.backgroundColor = '#4c566a';
        input.style.color = 'var(--text-color)';

        cell.innerHTML = '';
        cell.appendChild(input);
        input.focus();
        input.select();

        const saveEdit = async () => {
            const newValue = input.value.trim();
            if (newValue !== originalValue) {
                await updateParameterField(parameterId, field, newValue);
            }
            cell.textContent = newValue || originalValue;
        };

        input.addEventListener('blur', saveEdit);
        input.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                input.blur();
            }
        });
    }

    async function updateParameterField(parameterId, field, value) {
        const updateData = {};

        if (field === 'description_de') {
            const param = allParameters.find(p => p.id === parameterId);
            const translations = param.translations.map(t => ({
                ...t,
                description: t.language_code === 'de' ? value : t.description
            }));
            updateData.translations = translations;
        } else if (field === 'default_value') {
            updateData.default_value_json = value;
        } else {
            updateData[field] = value;
        }

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${parameterId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updateData)
            });

            if (response.ok) {
                const param = allParameters.find(p => p.id === parameterId);
                if (field === 'description_de') {
                    const deTranslation = param.translations.find(t => t.language_code === 'de');
                    if (deTranslation) deTranslation.description = value;
                } else if (field === 'default_value') {
                    param.default_value_json = value;
                } else {
                    param[field] = value;
                }
                statusMessage.textContent = 'Status: Änderung gespeichert.';
            } else {
                const result = await response.json();
                statusMessage.textContent = `Fehler beim Speichern: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    async function handleFlagChange(parameterId, event) {
        const field = event.target.dataset.field;
        const value = event.target.checked;

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${parameterId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ [field]: value })
            });

            if (response.ok) {
                const param = allParameters.find(p => p.id === parameterId);
                param[field] = value;
                statusMessage.textContent = 'Status: Flag gespeichert.';
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== SELECTION & RIGHT PANEL =====
    function selectParameter(param) {
        document.querySelectorAll('#parameterTableBody tr').forEach(r => r.classList.remove('selected'));
        const row = document.querySelector(`tr[data-parameter-id="${param.id}"]`);
        if (row) row.classList.add('selected');

        currentEditingParam = param;
        selectedRowParameterId = param.id; // Für "nach dieser Zeile einfügen"
        updateRightPanel(param);
    }

    function updateRightPanel(param) {
        const rightPanel = document.querySelector('.right-panel');
        if (!rightPanel || !param) return;

        rightPanel.querySelector('input[name="param_name"]').value = param.gdl_name || '';
        rightPanel.querySelector('select[name="param_type"]').value = param.gdl_type || 'Length';
        rightPanel.querySelector('select[name="param_function"]').value = param.function_group || 'Geometrie';
        rightPanel.querySelector('select[name="param_array_type"]').value = param.array_type || 'None';
        rightPanel.querySelector('input[name="flag_fix_name"]').checked = param.is_fix_name;
        rightPanel.querySelector('input[name="flag_unique"]').checked = param.flag_unique;
        rightPanel.querySelector('input[name="flag_bold"]').checked = param.flag_bold;
        rightPanel.querySelector('input[name="flag_child"]').checked = param.flag_child;
        rightPanel.querySelector('input[name="flag_hidden"]').checked = param.flag_hidden;
        rightPanel.querySelector('input[name="param_ui_page"]').value = param.ui_page || 0;
        rightPanel.querySelector('textarea[name="param_ui_code"]').value = param.ui_code || '';

        // Update translations
        document.querySelectorAll('.lang-content').forEach(langContent => {
            const lang = langContent.dataset.lang;
            const translation = param.translations.find(t => t.language_code === lang);

            if (translation) {
                langContent.querySelector('input[name="desc_lang"]').value = translation.description || '';
                langContent.querySelector('textarea[name="values_list_lang"]').value = translation.values_list || '';
                langContent.querySelector('textarea[name="ui_tooltip_lang"]').value = translation.ui_tooltip || '';
            } else {
                langContent.querySelector('input[name="desc_lang"]').value = '';
                langContent.querySelector('textarea[name="values_list_lang"]').value = '';
                langContent.querySelector('textarea[name="ui_tooltip_lang"]').value = '';
            }

            langContent.querySelector('input[name="default_val_lang"]').value = param.default_value_json || '';
        });
    }

    async function updateParameterFromRightPanel() {
        if (!currentEditingParam) return;

        const rightPanel = document.querySelector('.right-panel');
        const activeLang = rightPanel.querySelector('.lang-tab.active').dataset.lang;
        const activeLangContent = rightPanel.querySelector(`.lang-content[data-lang="${activeLang}"]`);

        const updateData = {
            gdl_name: rightPanel.querySelector('input[name="param_name"]').value,
            gdl_type: rightPanel.querySelector('select[name="param_type"]').value,
            function_group: rightPanel.querySelector('select[name="param_function"]').value,
            array_type: rightPanel.querySelector('select[name="param_array_type"]').value,
            is_fix_name: rightPanel.querySelector('input[name="flag_fix_name"]').checked,
            flag_unique: rightPanel.querySelector('input[name="flag_unique"]').checked,
            flag_bold: rightPanel.querySelector('input[name="flag_bold"]').checked,
            flag_child: rightPanel.querySelector('input[name="flag_child"]').checked,
            flag_hidden: rightPanel.querySelector('input[name="flag_hidden"]').checked,
            ui_page: parseInt(rightPanel.querySelector('input[name="param_ui_page"]').value),
            ui_code: rightPanel.querySelector('textarea[name="param_ui_code"]').value,
            default_value_json: activeLangContent.querySelector('input[name="default_val_lang"]').value,
            translations: [{
                language_code: activeLang,
                description: activeLangContent.querySelector('input[name="desc_lang"]').value,
                values_list: activeLangContent.querySelector('textarea[name="values_list_lang"]').value,
                ui_tooltip: activeLangContent.querySelector('textarea[name="ui_tooltip_lang"]').value
            }]
        };

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/${currentEditingParam.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(updateData)
            });

            if (response.ok) {
                Object.assign(currentEditingParam, updateData);
                await loadParameters(currentGdlObjectId);
                statusMessage.textContent = 'Status: Parameter aktualisiert.';
            }
        } catch (error) {
            statusMessage.textContent = `Fehler beim Speichern: ${error.message}`;
        }
    }

    // ===== ADD PARAMETER =====
    function showAddParameterDialog() {
        if (!currentGdlObjectId) {
            alert('Bitte wählen Sie zuerst ein GDL-Objekt.');
            return;
        }

        const paramName = prompt('Neuen Parameter erstellen\n\nBitte geben Sie den Parameternamen ein:');

        if (paramName && paramName.trim()) {
            addParameter(paramName.trim());
        }
    }

    async function addParameter(gdlName) {
        try {
            const requestBody = {
                gdl_object_id: currentGdlObjectId,
                gdl_name: gdlName,
                gdl_type: 'String',
                translations: [
                    { language_code: 'de', description: gdlName },
                    { language_code: 'en', description: gdlName }
                ]
            };

            // Wenn eine Zeile markiert ist, nach dieser einfügen
            if (selectedRowParameterId) {
                requestBody.insert_after_param_id = selectedRowParameterId;
            }

            const response = await fetch(`${API_BASE_URL}/parameters/create`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(requestBody)
            });

            const result = await response.json();

            if (response.ok) {
                statusMessage.textContent = `Status: Parameter "${gdlName}" erstellt.`;
                await loadParameters(currentGdlObjectId);
            } else {
                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== DELETE PARAMETERS =====
    function handleCheckboxChange(event) {
        const parameterId = parseInt(event.target.dataset.paramId);

        if (event.target.checked) {
            selectedParameterIds.add(parameterId);
        } else {
            selectedParameterIds.delete(parameterId);
        }

        updateDeleteButtonState();
    }

    function updateDeleteButtonState() {
        const deleteBtn = document.querySelector('.action-btn.delete-param');

        if (selectedParameterIds.size > 0) {
            deleteBtn.classList.remove('disabled');
        } else {
            deleteBtn.classList.add('disabled');
        }
    }

    async function deleteSelectedParameters() {
        if (selectedParameterIds.size === 0) return;

        const confirmed = confirm(`Möchten Sie wirklich ${selectedParameterIds.size} Parameter löschen?`);
        if (!confirmed) return;

        try {
            const response = await fetch(`${API_BASE_URL}/parameters/bulk-delete`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ parameter_ids: Array.from(selectedParameterIds) })
            });

            const result = await response.json();

            if (response.ok) {
                statusMessage.textContent = `Status: ${result.deleted_count} Parameter gelöscht.`;
                selectedParameterIds.clear();
                await loadParameters(currentGdlObjectId);
            } else {
                statusMessage.textContent = `Fehler: ${result.error}`;
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }

    // ===== DRAG & DROP REORDERING =====
    let draggedRow = null;

    function handleDragStart(e) {
        draggedRow = this;
        this.style.opacity = '0.4';
        e.dataTransfer.effectAllowed = 'move';
    }

    function handleDragOver(e) {
        if (e.preventDefault) {
            e.preventDefault();
        }
        e.dataTransfer.dropEffect = 'move';

        const targetRow = e.target.closest('tr');
        if (targetRow && targetRow !== draggedRow && targetRow.dataset.parameterId) {
            const rect = targetRow.getBoundingClientRect();
            const midpoint = rect.top + rect.height / 2;

            if (e.clientY < midpoint) {
                targetRow.parentNode.insertBefore(draggedRow, targetRow);
            } else {
                targetRow.parentNode.insertBefore(draggedRow, targetRow.nextSibling);
            }
        }

        return false;
    }

    function handleDrop(e) {
        if (e.stopPropagation) {
            e.stopPropagation();
        }
        return false;
    }

    async function handleDragEnd(e) {
        this.style.opacity = '1';

        const rows = Array.from(parameterTableBody.querySelectorAll('tr'));
        const orderedIds = rows.map(row => parseInt(row.dataset.parameterId)).filter(id => !isNaN(id));

        if (orderedIds.length > 0) {
            await saveParameterOrder(orderedIds);
        }
    }

    async function saveParameterOrder(orderedIds) {
        try {
            const response = await fetch(`${API_BASE_URL}/parameters/reorder`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ ordered_ids: orderedIds })
            });

            if (response.ok) {
                statusMessage.textContent = 'Status: Reihenfolge gespeichert.';
                const newOrder = [];
                orderedIds.forEach(id => {
                    const param = allParameters.find(p => p.id === id);
                    if (param) newOrder.push(param);
                });
                allParameters = newOrder;
            }
        } catch (error) {
            statusMessage.textContent = `Fehler beim Speichern der Reihenfolge: ${error.message}`;
        }
    }

    // ===== FILTER =====
    function filterParameters() {
        const filterText = filterInput.value.toLowerCase();
        const rows = parameterTableBody.querySelectorAll('tr');

        let visibleCount = 0;
        rows.forEach(row => {
            if (row.dataset.parameterId) {
                const text = row.textContent.toLowerCase();
                const isVisible = text.includes(filterText);
                row.style.display = isVisible ? '' : 'none';
                if (isVisible) visibleCount++;
            }
        });

        rowCountSpan.textContent = `Zeilen: ${visibleCount} / ${allParameters.length}`;
    }

    // ===== EXPORT XML =====
    async function exportXml(objectId) {
        if (!objectId) {
            alert('Kein GDL-Objekt geladen.');
            return;
        }

        try {
            statusMessage.textContent = 'Status: XML wird generiert...';

            const response = await fetch(`${API_BASE_URL}/objects/${objectId}/parameters/export`);

            if (response.ok) {
                const blob = await response.blob();
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `${currentGdlObjectName.replace('.gsm', '')}_parameters.xml`;
                document.body.appendChild(a);
                a.click();
                window.URL.revokeObjectURL(url);
                document.body.removeChild(a);

                statusMessage.textContent = 'Status: XML erfolgreich exportiert.';
            } else {
                statusMessage.textContent = 'Fehler beim XML-Export.';
            }
        } catch (error) {
            statusMessage.textContent = `Netzwerkfehler: ${error.message}`;
        }
    }
});
</script>
```

